const GLOSSARY_SECX = [
  { term:"API Security", definition:"Controls protecting application programming interfaces from attacks including injection, authentication bypass, broken object-level authorization, and excessive data exposure." },
  { term:"Attack Surface", definition:"The total set of exploitable vulnerabilities, entry points, and exposed components that an attacker could use to compromise a system or organization." },
  { term:"Attack Surface Management (ASM)", definition:"The continuous discovery, inventory, and monitoring of an organization's internet-facing and internal assets from an attacker's perspective. It identifies exposed, unknown, or shadow assets that expand exploitable risk." },
  { term:"Attestation", definition:"The process by which a system provides cryptographically signed evidence of its integrity and configuration state to a verifier. It allows a relying party to establish trust in a device's boot state or TEE before granting access." },
  { term:"Breach and Attack Simulation", definition:"Automated, continuous simulation of attacker tactics and techniques against real production environments to validate security control effectiveness." },
  { term:"Business Impact Analysis (BIA)", definition:"A process that identifies critical business functions and quantifies the operational and financial effects of their disruption. Its outputs, including RTO and RPO, drive continuity planning and recovery prioritization." },
  { term:"Certificate Authority (CA)", definition:"A trusted entity that issues, signs, and revokes digital certificates, vouching for the binding between a public key and an identity. Root and intermediate CAs form the hierarchical trust chain relied upon by clients." },
  { term:"Certificate Transparency", definition:"A framework of publicly auditable, append-only logs that record issued TLS certificates to detect misissuance. It allows domain owners and browsers to identify unauthorized or fraudulent certificates." },
  { term:"Chain of Custody", definition:"The documented, unbroken record of who collected, handled, transferred, and analyzed evidence and when. It preserves evidentiary integrity and admissibility by demonstrating the evidence was not altered." },
  { term:"Cloud Access Security Broker (CASB)", definition:"A policy enforcement point placed between cloud consumers and cloud providers to enforce visibility, compliance, data security, and threat protection. It can operate in API, forward-proxy, or reverse-proxy modes to control sanctioned and shadow IT usage." },
  { term:"Cloud Security Posture Management", definition:"Automated tools continuously monitoring cloud infrastructure configurations and comparing them against security best practices and compliance requirements." },
  { term:"Cloud Security Posture Management (CSPM)", definition:"A tool category that continuously assesses cloud configurations against best practices and compliance frameworks to detect misconfigurations and risk. It automates remediation and provides visibility into drift across multi-cloud environments." },
  { term:"Cloud Workload Protection Platform (CWPP)", definition:"A security solution focused on protecting server workloads across physical, virtual, container, and serverless environments. It provides runtime protection, vulnerability management, and system integrity monitoring regardless of where the workload runs." },
  { term:"Common Vulnerability Scoring System (CVSS)", definition:"A standardized framework for rating the severity of vulnerabilities using base, temporal, and environmental metric groups. It produces a 0 to 10 score to help organizations prioritize remediation consistently." },
  { term:"Conditional Access", definition:"A policy engine that evaluates signals such as user, device, location, and risk before granting, limiting, or blocking access. It enforces adaptive controls like step-up authentication when contextual risk is elevated." },
  { term:"Container Security", definition:"Security controls for containerized workloads including image scanning, runtime protection, network policies, and least-privilege configurations." },
  { term:"Crypto-Agility", definition:"The capability of a system to rapidly swap cryptographic algorithms, key sizes, and protocols without major re-engineering. It is essential for migrating to post-quantum algorithms and responding to newly discovered weaknesses." },
  { term:"Cryptographic Agility", definition:"The ability of a system to switch between cryptographic algorithms quickly when a current algorithm is deprecated or broken, without major architectural changes." },
  { term:"Data Classification", definition:"Organizing data into categories based on sensitivity and business value, determining appropriate handling, protection, and retention requirements for each category." },
  { term:"Data Loss Prevention (DLP)", definition:"A set of technologies and policies that detect and prevent unauthorized exfiltration of sensitive data at rest, in motion, and in use. It uses content inspection, contextual analysis, and fingerprinting to enforce data-handling rules across endpoints, networks, and cloud." },
  { term:"Deception Technology", definition:"Security controls including honeypots and honey tokens that lure attackers into fake environments, detecting intrusions and gathering threat intelligence." },
  { term:"Defense in Depth", definition:"A layered security strategy where multiple independent controls protect assets so that failure of one layer does not compromise overall security." },
  { term:"Digital Forensics", definition:"The disciplined process of identifying, preserving, analyzing, and presenting digital evidence while maintaining chain of custody. It supports incident response and legal proceedings through sound acquisition and analysis of volatile and non-volatile data." },
  { term:"Endpoint Detection and Response (EDR)", definition:"A solution that continuously monitors endpoints, records telemetry, and enables detection, investigation, and remediation of threats. It provides behavioral analytics and response actions such as host isolation at the device level." },
  { term:"Extended Detection and Response", definition:"Unified security platform integrating telemetry from endpoints, networks, cloud, and applications into a single detection and response capability." },
  { term:"Extended Detection and Response (XDR)", definition:"An approach that unifies telemetry across endpoints, network, cloud, and identity into a single correlated detection and response platform. It improves visibility and reduces alert fatigue by contextualizing signals across multiple domains." },
  { term:"Federated Identity", definition:"An arrangement that lets users authenticate once with a trusted identity provider and access multiple relying parties across domains. It relies on standards such as SAML, OAuth, and OpenID Connect to exchange assertions of identity and entitlement." },
  { term:"Governance, Risk, and Compliance (GRC)", definition:"An integrated approach to aligning security strategy with business objectives, managing risk, and meeting regulatory obligations. It provides the oversight structures, policies, and reporting that connect security operations to organizational accountability." },
  { term:"Hardware Security Module (HSM)", definition:"A tamper-resistant physical or cloud device that generates, stores, and processes cryptographic keys within a hardened boundary. It performs cryptographic operations without exposing key material and often meets FIPS 140-3 assurance levels." },
  { term:"Harvest Now, Decrypt Later", definition:"An adversary strategy of capturing encrypted data today to decrypt it once quantum computing matures. It elevates the urgency of adopting post-quantum cryptography for data with long confidentiality lifetimes." },
  { term:"Homomorphic Encryption", definition:"An encryption scheme that permits computation directly on ciphertext, producing an encrypted result that matches operations on the plaintext. It enables privacy-preserving processing of sensitive data by untrusted parties." },
  { term:"Identity and Access Management (IAM) Architecture", definition:"The structured design of authentication, authorization, and lifecycle processes governing how identities access resources. It encompasses directory services, federation, privileged access, and governance to enforce least privilege at scale." },
  { term:"Identity-Centric Security", definition:"An architectural approach treating verified identity as the primary security perimeter, replacing or augmenting traditional network-based perimeter controls." },
  { term:"Incident Response Lifecycle", definition:"The structured phases of preparation, detection and analysis, containment, eradication, recovery, and lessons learned defined by NIST SP 800-61. It provides a repeatable framework for managing security incidents effectively." },
  { term:"Indicators of Attack (IOA)", definition:"Behavioral signals that reveal an adversary's intent and actions in progress, independent of specific tools or malware. Unlike IOCs, they focus on the sequence of tactics being executed, enabling earlier detection." },
  { term:"Indicators of Compromise (IOC)", definition:"Forensic artifacts such as file hashes, IP addresses, domains, or registry keys that signal a system may be breached. They support detection and retrospective hunting but are often ephemeral and easily changed by adversaries." },
  { term:"Infrastructure as Code", definition:"Managing infrastructure through machine-readable configuration files rather than manual processes, enabling consistent, auditable, and version-controlled deployments." },
  { term:"Infrastructure as Code (IaC) Security", definition:"The practice of scanning declarative infrastructure definitions such as Terraform or CloudFormation for misconfigurations before deployment. It shifts cloud security left by embedding policy-as-code checks into the CI/CD pipeline." },
  { term:"Key Management", definition:"The full lifecycle governance of cryptographic keys including generation, distribution, storage, rotation, revocation, and destruction. Sound key management is essential because the security of encryption depends on protecting the keys, not the algorithm." },
  { term:"Lateral Movement", definition:"Techniques attackers use to progressively move through a network after gaining initial access, seeking to expand privileges and reach target assets." },
  { term:"Microsegmentation", definition:"Fine-grained network segmentation creating security zones at the workload or application level, minimizing the blast radius of a successful breach." },
  { term:"MITRE ATT&CK", definition:"A globally accessible knowledge base of adversary tactics, techniques, and procedures based on real-world observations, used to improve threat detection and response." },
  { term:"Mutual TLS (mTLS)", definition:"A TLS configuration in which both client and server present and validate certificates to authenticate each other. It is foundational to zero-trust service-to-service communication in microservice and mesh architectures." },
  { term:"OAuth 2.0", definition:"An authorization framework that allows a third-party application to obtain delegated, scoped access to a resource without exposing the user's credentials. It issues access tokens representing consented permissions rather than authenticating the user directly." },
  { term:"Online Certificate Status Protocol (OCSP) Stapling", definition:"A mechanism where the TLS server obtains and attaches a time-stamped CA-signed certificate status to the handshake. It improves performance and privacy by removing the need for clients to query the CA directly." },
  { term:"OpenID Connect (OIDC)", definition:"An identity layer built on top of OAuth 2.0 that adds authentication through an ID token in JWT format. It enables clients to verify user identity and obtain basic profile information in a standardized way." },
  { term:"Operational Technology (OT) Security", definition:"The protection of industrial control systems, SCADA, and physical process equipment from cyber threats. It prioritizes safety and availability, requiring specialized controls due to legacy protocols and constraints on patching." },
  { term:"Order of Volatility", definition:"The prioritized sequence for collecting digital evidence based on how quickly it degrades, from CPU registers and memory to disk and archives. Following it ensures the most fragile artifacts are captured before they are lost." },
  { term:"Perfect Forward Secrecy (PFS)", definition:"A property of key exchange, achieved with ephemeral Diffie-Hellman, ensuring that session keys are not derived from long-term secrets. Compromise of the server's private key cannot decrypt previously captured sessions." },
  { term:"Persistence", definition:"Techniques adversaries use to maintain access to systems across interruptions such as restarts, credential changes, or other disruptions." },
  { term:"Post-Quantum Cryptography", definition:"Cryptographic algorithms designed to remain secure against attacks from quantum computers, addressing the threat to current RSA and ECC-based systems." },
  { term:"Post-Quantum Cryptography (PQC)", definition:"Cryptographic algorithms designed to remain secure against attacks by quantum computers, including lattice- and hash-based schemes. NIST-standardized algorithms such as ML-KEM and ML-DSA address the future threat of quantum key breaking." },
  { term:"Privileged Access Management", definition:"Solutions and processes controlling, monitoring, and auditing the use of privileged accounts to prevent credential abuse and limit blast radius from compromise." },
  { term:"Privileged Access Management (PAM)", definition:"A discipline and toolset for securing, controlling, and monitoring elevated accounts and their credentials. It provides credential vaulting, session recording, just-in-time access, and rotation to reduce the attack surface of powerful accounts." },
  { term:"Public Key Infrastructure (PKI)", definition:"The framework of hardware, software, policies, and procedures that manages digital certificates and public-private key pairs. It binds identities to keys through certificate authorities to enable trust, encryption, and non-repudiation." },
  { term:"Purple Teaming", definition:"A collaborative exercise where offensive (red) and defensive (blue) teams work together to improve detection and response. It uses simulated attacks mapped to ATT&CK to validate and tune security controls iteratively." },
  { term:"Red Team", definition:"A dedicated group authorized to simulate real adversary attacks against an organization to test defenses, identify gaps, and improve security posture." },
  { term:"Resilience", definition:"An organization's ability to anticipate, withstand, recover from, and adapt to adverse conditions, including cyberattacks, without critical business function failure." },
  { term:"Risk-Informed Architecture", definition:"Security design decisions made based on analysis of actual threats, business impact, and risk tolerance rather than blanket compliance requirements." },
  { term:"SAML", definition:"Security Assertion Markup Language is an XML-based standard for exchanging authentication and authorization assertions between an identity provider and a service provider. It underpins web single sign-on across organizational boundaries." },
  { term:"SCIM", definition:"System for Cross-domain Identity Management is a standard for automating the provisioning and deprovisioning of user identities across applications. It reduces orphaned accounts by keeping identity lifecycle changes synchronized between systems." },
  { term:"Secure Access Service Edge (SASE)", definition:"A cloud-delivered architecture that converges networking (SD-WAN) and security functions such as SWG, CASB, ZTNA, and FWaaS into a single service. It applies identity- and context-aware policy at distributed edge points of presence close to users." },
  { term:"Secure Boot", definition:"A firmware mechanism that verifies the digital signature of each component in the boot chain before execution. It prevents rootkits and unauthorized bootloaders from loading by establishing a hardware root of trust." },
  { term:"Secure Design Principles", definition:"Foundational guidelines for building secure systems: least privilege, fail-secure, defense in depth, economy of mechanism, and complete mediation." },
  { term:"Secure Software Development", definition:"Integrating security requirements, design review, testing, and verification throughout the software development lifecycle to produce resilient applications." },
  { term:"Secure Web Gateway (SWG)", definition:"A control that inspects and filters web traffic to enforce acceptable-use policy, block malicious sites, and prevent data leakage. It provides URL filtering, TLS inspection, and malware scanning for outbound user connections." },
  { term:"Security Architecture", definition:"The set of design principles, guidelines, and models directing how security is structured and implemented across an enterprise to meet business and risk objectives." },
  { term:"Security Metrics", definition:"Quantifiable measures used to track the effectiveness of security controls, demonstrate risk reduction, and communicate security posture to leadership." },
  { term:"Security Orchestration", definition:"The automated coordination of multiple security tools and processes to reduce manual effort, accelerate response, and ensure consistent handling of security events." },
  { term:"Security Service Edge (SSE)", definition:"The security-focused subset of SASE that unifies Secure Web Gateway, Cloud Access Security Broker, and Zero Trust Network Access. It delivers consistent policy enforcement for cloud, web, and private application access without the networking components." },
  { term:"SIEM", definition:"Security Information and Event Management aggregates and correlates log and event data from across the enterprise for detection, alerting, and compliance. It provides centralized analysis, retention, and dashboards to identify security incidents in near real time." },
  { term:"SOAR", definition:"Security Orchestration, Automation, and Response platforms integrate disparate tools and codify incident workflows into automated playbooks. They accelerate triage and response by reducing manual, repetitive analyst tasks and enforcing consistency." },
  { term:"Software Bill of Materials (SBOM)", definition:"A formal, machine-readable inventory of all components, libraries, and dependencies within a software product. It enables rapid identification of exposure to newly disclosed vulnerabilities across the software supply chain." },
  { term:"Software-Defined Perimeter (SDP)", definition:"An architecture that dynamically creates one-to-one encrypted connections between users and the resources they access, rendering infrastructure invisible to unauthorized parties. It authenticates and authorizes before any network connectivity is established." },
  { term:"Supply Chain Risk Management", definition:"The identification, assessment, and mitigation of risks introduced by vendors, software dependencies, and third-party services. It addresses threats such as tampered components, compromised updates, and fourth-party concentration risk." },
  { term:"Supply Chain Security", definition:"Security measures addressing risks introduced through third-party software, hardware, or services integrated into an organization's systems." },
  { term:"Threat Hunting", definition:"A proactive, hypothesis-driven practice of searching networks and endpoints for threats that evade automated detection. Hunters use intelligence, behavioral analytics, and the ATT&CK framework to uncover stealthy adversary activity." },
  { term:"Threat Intelligence", definition:"Evidence-based knowledge about existing or emerging threats that can be used to inform security decisions, including context, mechanisms, indicators, and actionable advice." },
  { term:"Threat Modeling", definition:"A structured process for identifying potential threats to a system during design, analyzing their likelihood and impact, and determining appropriate mitigations." },
  { term:"Trusted Execution Environment (TEE)", definition:"An isolated, hardware-enforced region of a processor that protects code and data confidentiality and integrity during execution. Examples include Intel SGX and ARM TrustZone, enabling confidential computing on untrusted hosts." },
  { term:"Trusted Platform Module (TPM)", definition:"A dedicated hardware chip that provides secure key storage, platform integrity measurements, and cryptographic functions. It anchors capabilities such as measured boot, disk encryption key sealing, and remote attestation." },
  { term:"User and Entity Behavior Analytics (UEBA)", definition:"An analytics technique that baselines normal behavior of users and entities and flags statistically anomalous activity. It helps detect insider threats, compromised accounts, and lateral movement that signature-based tools miss." },
  { term:"Vulnerability Management", definition:"The continuous cycle of discovering, assessing, prioritizing, remediating, and verifying weaknesses across assets. It incorporates risk-based prioritization using factors like exploitability, exposure, and business criticality." },
  { term:"Zero Trust", definition:"A security strategy based on 'never trust, always verify' — no implicit trust is granted to any user, device, or network location; all access must be explicitly verified." },
  { term:"Zero Trust Architecture", definition:"A security model that eliminates implicit trust and continuously verifies every access request based on identity, device posture, and context. It enforces least-privilege access and assumes that threats exist both inside and outside the network perimeter." },
  { term:"Zero Trust Network Access (ZTNA)", definition:"A technology that grants application access based on identity and context rather than network location, brokering connections through a policy enforcement point. It hides applications from the public internet and replaces implicit VPN trust with per-session verification." },
  { term:"SPIFFE/SPIRE", definition:"SPIFFE (Secure Production Identity Framework For Everyone) is a standard for cryptographic workload identity using SVIDs (X.509 or JWT), while SPIRE is its reference implementation that attests workloads and issues short-lived identities. Together they replace static secrets with attested, rotating identities in zero-trust service-to-service authentication." },
  { term:"Service Mesh", definition:"An infrastructure layer (e.g., Istio, Linkerd) that transparently handles service-to-service communication, mutual TLS, observability, and traffic policy via sidecar proxies. It decouples security and reliability logic from application code, enabling consistent mTLS and authorization across microservices." },
  { term:"eBPF", definition:"Extended Berkeley Packet Filter runs sandboxed programs in the Linux kernel without changing kernel source or loading modules, enabling deep, low-overhead observability and enforcement. Security tools use eBPF for runtime threat detection, network policy enforcement, and syscall-level monitoring in cloud-native environments." },
  { term:"Sidecar Proxy", definition:"A helper container deployed alongside an application container in the same pod that intercepts all inbound and outbound traffic. It offloads mTLS, retries, telemetry, and policy enforcement from the application, forming the data plane of a service mesh." },
  { term:"Confidential Computing", definition:"A paradigm that protects data in use by performing computation inside hardware-based Trusted Execution Environments (TEEs) isolated from the host OS, hypervisor, and cloud operator. It closes the gap left by encryption at rest and in transit by keeping data encrypted even during processing." },
  { term:"Secure Enclave", definition:"A hardware-isolated region of a processor (e.g., Intel SGX, Apple Secure Enclave) that protects code and data with memory encryption and access controls, even against a compromised OS. It underpins confidential computing and secure key storage." },
  { term:"Attestation (Remote/Local)", definition:"The process by which a system cryptographically proves its identity and integrity state to a verifier. Local attestation validates components within one platform, while remote attestation lets an external relying party verify a TEE's measurements before entrusting it with secrets." },
  { term:"Measured Boot", definition:"A boot process that cryptographically hashes each firmware and software component and extends the measurements into TPM Platform Configuration Registers before execution. Unlike Secure Boot, it records rather than blocks, enabling later attestation of the boot chain's integrity." },
  { term:"TPM PCR", definition:"Platform Configuration Registers are shielded TPM locations that hold cumulative hash values of measured boot components via an extend operation. PCR values are used to seal secrets so they unseal only when the platform is in a known-good state." },
  { term:"Hardware Root of Trust", definition:"An immutable, tamper-resistant hardware component that anchors a chain of trust for secure boot, key storage, and attestation. Because it cannot be modified by software, all higher-level trust decisions ultimately derive from it." },
  { term:"Firmware Security (UEFI/SPI)", definition:"The protection of low-level firmware such as UEFI stored on SPI flash from tampering, implants, and persistence below the OS. Controls include Secure Boot, signed firmware updates, SPI write protection, and Boot Guard to prevent bootkit and rootkit attacks." },
  { term:"Supply Chain Attack", definition:"An attack that compromises a trusted third-party component, dependency, build system, or update channel to reach downstream victims. Examples include poisoned software updates and malicious open-source packages, exploiting implicit trust in vendors and repositories." },
  { term:"SLSA Framework", definition:"Supply-chain Levels for Software Artifacts is a graded security framework (levels 1-4) that defines requirements for build integrity and provenance. Higher levels demand hermetic, reproducible builds and signed, verifiable provenance to resist tampering." },
  { term:"SBOM (SPDX/CycloneDX)", definition:"A Software Bill of Materials is a machine-readable inventory of all components and dependencies in a product, expressed in standards like SPDX or CycloneDX. It enables rapid identification of vulnerable components across an organization when new CVEs emerge." },
  { term:"Sigstore/Cosign", definition:"Sigstore is an open-source ecosystem for signing, verifying, and proving provenance of software artifacts, and Cosign is its container-signing tool. It uses keyless signing tied to OIDC identities and transparency logs to simplify supply-chain trust." },
  { term:"Provenance", definition:"Verifiable metadata describing how, when, and by whom a software artifact was produced, including build inputs and environment. Cryptographically signed provenance lets consumers confirm an artifact originated from a trusted, unmodified build pipeline." },
  { term:"Software Attestation", definition:"A signed statement asserting facts about an artifact, such as its build provenance, SBOM, or test results, bound to the artifact's digest. Verification policies consume attestations to admit only artifacts meeting supply-chain requirements." },
  { term:"Certificate Transparency Log", definition:"A publicly auditable, append-only log of issued TLS certificates that lets domain owners detect mis-issuance. Browsers require SCTs (Signed Certificate Timestamps) proving a certificate was logged, deterring rogue or unauthorized CA issuance." },
  { term:"OCSP Stapling", definition:"A performance and privacy optimization where a TLS server obtains a time-stamped, CA-signed OCSP response and staples it to the handshake. This avoids clients contacting the OCSP responder directly, reducing latency and preventing the CA from tracking users." },
  { term:"Perfect Forward Secrecy", definition:"A property of key-exchange (e.g., ephemeral Diffie-Hellman) ensuring that compromise of a server's long-term private key cannot decrypt previously captured sessions. Each session uses unique ephemeral keys that are discarded after use." },
  { term:"Post-Quantum Cryptography (CRYSTALS-Kyber/Dilithium)", definition:"Cryptographic algorithms designed to resist attacks by quantum computers, standardized by NIST. CRYSTALS-Kyber provides lattice-based key encapsulation (ML-KEM) and CRYSTALS-Dilithium provides lattice-based digital signatures (ML-DSA)." },
  { term:"Key Escrow / Recovery Agent", definition:"Key escrow stores copies of cryptographic keys with a trusted third party so data can be recovered if keys are lost, while a recovery agent is an authorized entity able to decrypt others' protected data. Both introduce recovery capability at the cost of expanding the trust boundary." },
  { term:"Envelope Encryption", definition:"A scheme where a data encryption key (DEK) encrypts the data and a separate key encryption key (KEK), often in an HSM or KMS, encrypts the DEK. It enables efficient bulk encryption, easy key rotation, and centralized KEK control." },
  { term:"BYOK/HYOK", definition:"Bring Your Own Key lets customers import their own key material into a cloud KMS, while Hold Your Own Key keeps keys entirely in customer-controlled hardware external to the cloud. HYOK offers stronger sovereignty because the provider never possesses the key." },
  { term:"Format-Preserving Encryption", definition:"An encryption method that produces ciphertext in the same format and length as the plaintext, such as a 16-digit number remaining a valid 16-digit number. It enables encrypting data in legacy systems and fixed schemas without altering field structures." },
  { term:"Tokenization vs Masking", definition:"Tokenization replaces sensitive data with a non-sensitive surrogate mapped in a secure vault, allowing reversible retrieval, whereas masking irreversibly obscures data (e.g., showing only last four digits). Tokenization removes data from scope while masking limits exposure in views." },
  { term:"Data Sovereignty", definition:"The principle that data is subject to the laws and governance of the jurisdiction in which it is physically stored or processed. It drives requirements for in-region storage, provider selection, and controls over foreign government access." },
  { term:"Confidential VMs", definition:"Virtual machines whose memory is hardware-encrypted (e.g., AMD SEV-SNP, Intel TDX) so the hypervisor and cloud operator cannot read guest data or code in use. They extend confidential computing to full VMs without application changes." },
  { term:"CASB (Inline/API)", definition:"A Cloud Access Security Broker enforces security policy between users and cloud services. Inline (proxy) mode intercepts live traffic for real-time control, while API mode connects to SaaS APIs out-of-band for visibility, DLP, and configuration checks on data at rest." },
  { term:"CSPM/CWPP/CNAPP/CIEM", definition:"CSPM detects cloud misconfigurations and compliance drift, CWPP protects workloads (VMs, containers, serverless) at runtime, CIEM manages cloud entitlements and least privilege, and CNAPP is a converged platform unifying all of these across the application lifecycle." },
  { term:"SASE/SSE Components", definition:"Secure Access Service Edge converges networking (SD-WAN) and security as a cloud-delivered service, while Security Service Edge is the security-only subset comprising SWG, CASB, ZTNA, and FWaaS. Both deliver policy at the edge close to users regardless of location." },
  { term:"ZTNA vs VPN", definition:"Zero Trust Network Access grants per-application access after continuous identity and posture verification, hiding resources behind a broker, whereas a traditional VPN grants broad network-level access after a single authentication. ZTNA reduces lateral movement and shrinks the attack surface." },
  { term:"SDP Controller", definition:"In a Software-Defined Perimeter, the controller authenticates and authorizes clients and then dynamically provisions encrypted connections to authorized gateways/hosts. Resources remain invisible (dark) until a client is verified, implementing a need-to-know network model." },
  { term:"Deception Technology / Honeypot / Honeytoken", definition:"Deception technology plants decoy systems, credentials, and data to detect and mislead attackers with high-fidelity alerts. A honeypot is a decoy host that lures attackers, while a honeytoken is a fake credential or record that signals compromise when accessed." },
  { term:"Threat Hunting Hypothesis", definition:"A testable assumption about adversary presence or behavior that drives a proactive hunt, often derived from threat intelligence, ATT&CK techniques, or anomalies. It focuses data collection and analysis rather than passively waiting for alerts." },
  { term:"Pyramid of Pain", definition:"A model ranking indicators by how much disruption denying them causes an adversary, from trivial (hash values, IPs) to painful (tools, TTPs). Defending against higher-tier indicators forces attackers to change behavior, delivering more durable defense." },
  { term:"Diamond Model", definition:"An intrusion analysis framework linking four core features of any event: adversary, capability, infrastructure, and victim. Pivoting across these relationships helps analysts correlate events and attribute campaigns." },
  { term:"MITRE ATT&CK / D3FEND / CAR", definition:"ATT&CK is a knowledge base of adversary tactics and techniques from real-world observations, D3FEND is a complementary catalog of defensive countermeasures, and CAR (Cyber Analytics Repository) provides validated detection analytics mapped to ATT&CK." },
  { term:"TTP", definition:"Tactics, Techniques, and Procedures describe how adversaries operate: tactics are goals, techniques are general methods, and procedures are specific implementations. TTPs sit at the top of the Pyramid of Pain because they are hardest for attackers to change." },
  { term:"IOC vs IOA", definition:"Indicators of Compromise are forensic artifacts (hashes, IPs, domains) showing an intrusion has occurred, while Indicators of Attack describe adversary intent and behavior in progress. IOAs enable earlier, behavior-based detection independent of known signatures." },
  { term:"Cyber Threat Intelligence (Strategic/Operational/Tactical)", definition:"CTI is analyzed information about threats consumed at three levels: strategic (high-level risk trends for executives), operational (campaign and actor context for defenders), and tactical (specific IOCs and TTPs for tools and analysts)." },
  { term:"STIX/TAXII", definition:"STIX is a standardized language for representing structured cyber threat intelligence, and TAXII is the transport protocol for exchanging that intelligence between systems. Together they enable automated, interoperable sharing of indicators and context." },
  { term:"Sandboxing/Detonation", definition:"Executing suspicious files or URLs in an isolated, instrumented environment to observe malicious behavior without risking production systems. Advanced malware may employ anti-analysis and evasion to detect sandboxes and delay detonation." },
  { term:"UEBA", definition:"User and Entity Behavior Analytics establishes behavioral baselines for users and devices and uses machine learning to flag anomalous deviations. It excels at detecting insider threats, compromised accounts, and low-and-slow attacks missed by signatures." },
  { term:"SOAR Playbook", definition:"A codified, often automated workflow in a Security Orchestration, Automation, and Response platform that executes response steps such as enrichment, containment, and ticketing. Playbooks reduce mean time to respond and enforce consistent, repeatable incident handling." },
  { term:"EDR/XDR/MDR", definition:"EDR monitors and responds to threats on endpoints, XDR correlates telemetry across endpoints, network, cloud, and identity for unified detection, and MDR is a managed service delivering these capabilities with human analysts. They differ in scope and staffing model." },
  { term:"Purple Team", definition:"A collaborative exercise where offensive (red) and defensive (blue) teams work together in real time to test and improve detection and response. The goal is knowledge transfer and measurable defensive improvement rather than a pass/fail engagement." },
  { term:"Attack Surface Management", definition:"The continuous discovery, inventory, and monitoring of an organization's internet-facing and internal assets to reduce exploitable exposure. External ASM focuses on discovering unknown or shadow assets an attacker could target." },
  { term:"CVSS Temporal/Environmental", definition:"CVSS base metrics score intrinsic vulnerability severity, temporal metrics adjust for exploit maturity and remediation status over time, and environmental metrics tailor the score to an organization's specific asset criticality and controls. The latter two yield context-aware risk ratings." },
  { term:"EPSS", definition:"The Exploit Prediction Scoring System estimates the probability that a vulnerability will be exploited in the wild within 30 days. It complements CVSS severity by helping prioritize remediation toward vulnerabilities most likely to be attacked." },
  { term:"KEV Catalog", definition:"CISA's Known Exploited Vulnerabilities catalog is an authoritative list of vulnerabilities confirmed to be actively exploited. It provides remediation deadlines for federal agencies and serves as a high-priority patching signal for all organizations." },
  { term:"Vulnerability Prioritization", definition:"The risk-based process of ranking remediation using severity, exploitability (EPSS/KEV), asset value, exposure, and compensating controls rather than CVSS alone. It focuses limited resources on the vulnerabilities posing genuine organizational risk." },
  { term:"SAST/DAST/IAST/RASP", definition:"SAST analyzes source code statically for flaws, DAST tests a running application from the outside, IAST instruments the app to combine both during testing, and RASP protects the app at runtime by detecting and blocking attacks from within. They cover different stages and blind spots." },
  { term:"Fuzzing", definition:"An automated testing technique that feeds malformed, random, or mutated inputs to a program to trigger crashes, memory errors, or unexpected behavior. Coverage-guided fuzzers use instrumentation to explore new code paths and uncover deep vulnerabilities." },
  { term:"Dependency Confusion", definition:"A supply-chain attack where an attacker publishes a malicious package to a public registry using the same name as an internal private package. Misconfigured package managers may pull the higher-versioned public package, executing attacker code in the build." },
  { term:"Business Email Compromise", definition:"A social-engineering fraud in which attackers impersonate executives, vendors, or partners via email to trick employees into wiring funds or disclosing data. It typically relies on account takeover or spoofing rather than malware, evading traditional defenses." },
  { term:"Living off the Land (LOLBins)", definition:"An attack technique that abuses legitimate, signed system binaries and tools (e.g., PowerShell, certutil, WMI) to perform malicious actions. Because the tools are trusted and native, this evades allowlisting and signature-based detection." },
  { term:"Fileless Malware", definition:"Malicious activity that operates in memory or via legitimate tools and scripts without writing traditional executable files to disk. It evades file-based scanning and often persists through registry entries, scheduled tasks, or WMI subscriptions." },
  { term:"Command and Control (C2)", definition:"The infrastructure and channels attackers use to remotely direct compromised hosts, issue commands, and exfiltrate data. Modern C2 often hides in encrypted web traffic, uses domain fronting, or leverages legitimate cloud services to blend in." },
  { term:"Beaconing", definition:"The periodic, often jittered check-in traffic a compromised host sends to its C2 server to receive instructions. Detecting regular timing patterns and consistent destinations is a key network-based indicator of an active implant." },
  { term:"DNS Tunneling", definition:"A covert channel technique that encodes data or C2 traffic within DNS queries and responses to bypass firewalls that permit DNS. Detection relies on analyzing anomalous query volume, entropy, and subdomain length." },
  { term:"Data Exfiltration", definition:"The unauthorized transfer of data out of an organization, whether via network channels, removable media, or cloud uploads. Adversaries often compress, encrypt, and stage data, then exfiltrate over encrypted or trusted channels to evade DLP." },
  { term:"GRC Automation", definition:"The use of tooling to automate governance, risk, and compliance activities such as control mapping, evidence collection, and continuous assessment. It reduces manual audit effort and provides near-real-time visibility into control effectiveness." },
  { term:"Continuous Compliance", definition:"An approach that continuously validates systems against regulatory and policy requirements using automated checks rather than periodic audits. It detects configuration drift and control failures immediately, treating compliance as an ongoing state." },
  { term:"Privacy Engineering", definition:"The discipline of embedding privacy protections into system architecture and development through techniques like data minimization, de-identification, and privacy-by-design. It operationalizes privacy requirements as concrete technical controls rather than policy alone." },
  { term:"Data Protection Impact Assessment", definition:"A structured process required for high-risk processing under GDPR that identifies and mitigates privacy risks before processing begins. It documents necessity, proportionality, risks to data subjects, and safeguards." },
  { term:"Right to be Forgotten", definition:"A data-subject right (GDPR Article 17) to have personal data erased under certain conditions, such as when it is no longer necessary or consent is withdrawn. It imposes architectural requirements for locating and deleting data across systems and backups." },
  { term:"Cross-Border Data Transfer", definition:"The movement of personal data across national jurisdictions, which regulations like GDPR restrict absent adequate protections. Mechanisms include adequacy decisions, Standard Contractual Clauses, and Binding Corporate Rules to legitimize transfers." },
  { term:"Domain Fronting", definition:"A technique that hides the true destination of traffic by using a benign domain in the TLS SNI/HTTPS layer while routing to a different host via the Host header on a shared CDN. Attackers use it to disguise C2 as legitimate cloud traffic." },
  { term:"Kerberoasting", definition:"An Active Directory attack where an authenticated user requests service tickets (TGS) for accounts with SPNs and cracks them offline to recover service-account passwords. It exploits weak service-account passwords and the RC4 encryption of tickets." },
  { term:"Golden/Silver Ticket", definition:"Kerberos forgery attacks: a Golden Ticket forges TGTs using the compromised KRBTGT hash for domain-wide persistence, while a Silver Ticket forges service tickets using a service account's hash for targeted access. Both grant stealthy, long-lived access." },
  { term:"Pass-the-Hash / Pass-the-Ticket", definition:"Credential-reuse attacks where an adversary authenticates using a stolen NTLM hash or a captured Kerberos ticket without knowing the plaintext password. They enable lateral movement by abusing single sign-on mechanisms." },
  { term:"DCSync", definition:"An attack that abuses the directory replication (DRSUAPI) protocol to impersonate a domain controller and request password hashes for any account, including KRBTGT. It requires replication privileges and is a key step toward domain dominance." },
  { term:"OAuth 2.0 / OIDC Flows", definition:"OAuth 2.0 is an authorization framework delegating access via tokens, and OpenID Connect layers identity (ID tokens) on top. The Authorization Code flow with PKCE is preferred for public clients, replacing the deprecated Implicit flow." },
  { term:"PKCE", definition:"Proof Key for Code Exchange strengthens the OAuth authorization code flow by binding the token request to a client-generated secret (code verifier/challenge). It prevents authorization-code interception attacks on public and mobile clients." },
  { term:"SAML Assertion", definition:"An XML-based security token issued by an identity provider asserting a subject's authentication and attributes to a service provider in federated SSO. Weaknesses like XML signature wrapping can allow assertion forgery if validation is flawed." },
  { term:"Just-in-Time Access", definition:"An access model that grants elevated privileges only for a limited time window when needed and revokes them automatically afterward. It minimizes standing privilege and shrinks the window of opportunity for credential abuse." },
  { term:"FIDO2 / WebAuthn", definition:"An open authentication standard using public-key cryptography and hardware authenticators to provide phishing-resistant, passwordless login. Private keys never leave the device, and signatures are bound to the origin, defeating credential replay and phishing." },
  { term:"Secrets Management", definition:"The centralized storage, rotation, access control, and auditing of credentials, API keys, and certificates using tools like HashiCorp Vault. It eliminates hardcoded secrets and enables dynamic, short-lived credentials for applications." },
  { term:"HSM (Hardware Security Module)", definition:"A tamper-resistant hardware device that generates, stores, and uses cryptographic keys within a hardened boundary and provides high-assurance operations. FIPS 140-3 validated HSMs ensure keys never leave the module in plaintext." },
  { term:"Container Escape", definition:"An attack that breaks out of a container's isolation to gain access to the host or other containers, often via kernel vulnerabilities, privileged containers, or misconfigured mounts. It undermines the trust boundary between multi-tenant workloads." },
  { term:"Kubernetes RBAC", definition:"Role-Based Access Control in Kubernetes governs which subjects can perform which verbs on which API resources via Roles and RoleBindings. Overly permissive bindings, especially cluster-admin, are a common path to cluster compromise." },
  { term:"Admission Controllers", definition:"Kubernetes plugins that intercept API requests after authentication to validate or mutate objects before persistence, enforcing policy via tools like OPA Gatekeeper or Kyverno. They block noncompliant workloads such as privileged or unsigned images." },
  { term:"OPA / Rego", definition:"Open Policy Agent is a general-purpose policy engine that decouples authorization decisions from application code, using the declarative Rego language. It enables consistent policy-as-code across Kubernetes admission, microservices, and CI/CD." },
  { term:"Infrastructure as Code Security", definition:"The practice of scanning IaC templates (Terraform, CloudFormation) for misconfigurations and policy violations before deployment. Shifting security left into IaC prevents insecure infrastructure from ever being provisioned." },
  { term:"Immutable Infrastructure", definition:"A deployment model where servers are never modified after provisioning; changes are made by replacing instances built from versioned images. It reduces configuration drift, simplifies rollback, and limits persistence opportunities for attackers." },
  { term:"GitOps", definition:"An operational model that uses a Git repository as the single source of truth for declarative infrastructure and application state, with automated reconciliation. It provides auditable change control and easy rollback but makes repository security critical." },
  { term:"Serverless Security", definition:"Securing function-as-a-service workloads where the provider manages the runtime, shifting focus to function permissions, event-injection, dependency risk, and short-lived execution. Least-privilege IAM roles per function limit blast radius." },
  { term:"WAF vs RASP", definition:"A Web Application Firewall inspects and filters HTTP traffic at the network perimeter using rules and signatures, while RASP is embedded in the application runtime with full context of execution. RASP reduces false positives by seeing actual code behavior." },
  { term:"API Gateway Security", definition:"Controls at an API gateway including authentication, rate limiting, schema validation, and threat protection that centralize enforcement for microservice and public APIs. It mitigates OWASP API risks like broken object-level authorization and excessive data exposure." },
  { term:"mTLS", definition:"Mutual TLS requires both client and server to present and validate X.509 certificates, authenticating each party rather than only the server. It is foundational to zero-trust service meshes for verifying workload identity on every connection." },
  { term:"Certificate Pinning", definition:"A technique where an application hardcodes or restricts which certificates or public keys it will accept for a given host, rejecting others even if CA-signed. It defends against fraudulent certificates and man-in-the-middle interception but complicates rotation." },
  { term:"DNSSEC", definition:"Domain Name System Security Extensions add cryptographic signatures to DNS records so resolvers can verify authenticity and integrity. It prevents cache poisoning and spoofing but does not provide confidentiality of queries." },
  { term:"DoH / DoT", definition:"DNS over HTTPS and DNS over TLS encrypt DNS queries to protect confidentiality and prevent tampering or eavesdropping. While improving privacy, they can complicate enterprise monitoring and policy enforcement by hiding DNS from inspection." },
  { term:"BGP Hijacking", definition:"An attack or misconfiguration where a network announces IP prefixes it does not own, redirecting or intercepting internet traffic. RPKI and route origin validation mitigate hijacks by cryptographically verifying legitimate prefix origins." },
  { term:"Air Gap / Data Diode", definition:"An air gap physically isolates a network from untrusted networks, while a data diode enforces strictly one-way data flow using hardware. Both protect high-assurance environments like OT and classified systems from bidirectional compromise." },
  { term:"Purdue Model", definition:"A reference architecture for industrial control systems that segments environments into hierarchical levels from field devices (Level 0) to enterprise IT (Levels 4-5). It structures OT/IT segmentation and defines controlled conduits between zones." },
  { term:"OT/ICS Security", definition:"The protection of operational technology and industrial control systems such as SCADA, PLCs, and DCS, where availability and safety outweigh confidentiality. Constraints include legacy protocols, patching difficulty, and real-time requirements demanding compensating controls." },
  { term:"Safety Instrumented System", definition:"An independent control system in industrial plants designed to bring a process to a safe state when hazardous conditions occur. Attacks like TRITON that target SIS logic can cause physical damage or endanger lives, making SIS integrity critical." },
  { term:"Threat Modeling (STRIDE/PASTA/DREAD)", definition:"A structured practice of identifying and prioritizing threats during design; STRIDE categorizes threat types, PASTA is a risk-centric seven-stage process, and DREAD scores risk across five factors. Threat modeling shifts security analysis to the architecture phase." },
  { term:"Attack Trees", definition:"A hierarchical diagram that decomposes an attacker's ultimate goal at the root into progressively finer sub-goals and methods at the branches. They help analysts reason systematically about attack paths and identify the most cost-effective mitigations." },
  { term:"Cyber Kill Chain", definition:"Lockheed Martin's model describing the sequential stages of an intrusion from reconnaissance through actions on objectives. Defenders aim to detect and disrupt the adversary as early in the chain as possible to prevent objective completion." },
  { term:"MITRE Engage", definition:"A framework for planning and discussing adversary engagement, deception, and denial operations to actively influence attacker behavior. It provides a structured vocabulary for defensive deception strategy beyond passive detection." },
  { term:"Zero Trust Architecture (NIST 800-207)", definition:"A security model that assumes no implicit trust based on network location and continuously verifies every access request using identity, device, and context. NIST 800-207 defines core components including the policy engine, policy administrator, and policy enforcement point." },
  { term:"Policy Decision/Enforcement Point", definition:"In access-control and zero-trust architectures, the PDP evaluates policy to render an access decision while the PEP intercepts requests and enforces that decision. Separating decision from enforcement enables centralized, consistent policy across distributed resources." },
  { term:"ABAC vs RBAC", definition:"Role-Based Access Control grants permissions through predefined roles, while Attribute-Based Access Control makes dynamic decisions using attributes of the subject, resource, action, and environment. ABAC offers finer-grained, context-aware control at the cost of greater complexity." },
  { term:"Data Loss Prevention (Network/Endpoint/Cloud)", definition:"DLP technologies detect and prevent unauthorized movement of sensitive data across network egress, endpoints, and cloud services using content inspection and context. Effective DLP relies on accurate data classification and policies tuned to reduce false positives." },
  { term:"Data Classification / Labeling", definition:"The process of categorizing data by sensitivity and applying persistent labels that drive protection controls such as encryption, access, and DLP. Automated classification and labeling enable consistent, policy-driven handling as data moves and is shared." },
  { term:"Quantum Key Distribution", definition:"A method that uses quantum mechanics, such as photon polarization, to distribute encryption keys with the ability to detect any eavesdropping. Unlike post-quantum algorithms, QKD provides physics-based key exchange but requires specialized hardware and links." },
  { term:"Side-Channel Attack", definition:"An attack that infers secrets by measuring physical or micro-architectural leakage such as power consumption, timing, electromagnetic emissions, or cache behavior. Countermeasures include constant-time algorithms, masking, and noise injection." },
  { term:"Rowhammer", definition:"A hardware vulnerability where repeatedly accessing DRAM rows induces bit flips in adjacent rows, enabling privilege escalation or cryptographic key corruption. Mitigations include target row refresh, ECC memory, and increased refresh rates." },
  { term:"Speculative Execution Attacks", definition:"Micro-architectural attacks like Spectre and Meltdown that exploit CPU speculative execution to leak protected memory across trust boundaries via cache side channels. Mitigations combine microcode updates, kernel page-table isolation, and compiler barriers." },
  { term:"Trusted Platform Module", definition:"A dedicated cryptoprocessor chip providing secure key generation and storage, platform integrity measurement via PCRs, and attestation. It anchors features like measured boot, disk encryption key sealing, and device identity." },
  { term:"Firmware Resiliency (NIST 800-193)", definition:"A guideline defining principles of protection, detection, and recovery for platform firmware to withstand and recover from corruption. It ensures devices can restore firmware to a known-good state after a compromise or failed update." },
  { term:"Software Composition Analysis", definition:"Tooling that inventories open-source and third-party components in a codebase and identifies known vulnerabilities and license risks. SCA feeds SBOM generation and is central to managing supply-chain and dependency risk." },
  { term:"CI/CD Pipeline Security", definition:"Protecting the build and deployment pipeline against tampering by securing runners, secrets, artifact integrity, and access to the pipeline configuration. Compromised pipelines enable large-scale supply-chain attacks by injecting malicious code into trusted builds." },
  { term:"Signed Commits / Signed Artifacts", definition:"The practice of cryptographically signing source commits and build outputs so their author and integrity can be verified. Signature verification in the pipeline and at deployment prevents unauthorized or tampered code from progressing." },
  { term:"Zero Knowledge Proof", definition:"A cryptographic protocol allowing one party to prove knowledge of a fact to another without revealing the underlying information. Applications include privacy-preserving authentication and verifiable credentials where minimal disclosure is required." },
  { term:"Differential Privacy", definition:"A mathematical framework that adds calibrated noise to datasets or query results so individual records cannot be re-identified while preserving aggregate accuracy. The privacy budget (epsilon) quantifies the trade-off between privacy and utility." },
  { term:"Federated Learning", definition:"A machine-learning approach that trains models across decentralized devices holding local data, sharing only model updates rather than raw data. It reduces central data exposure but introduces risks like model poisoning and inference attacks on updates." },
  { term:"Adversarial Machine Learning", definition:"Attacks that manipulate ML systems through crafted inputs (evasion), poisoned training data, model extraction, or inference of training data. Defenses include adversarial training, input validation, and robust model monitoring." },
  { term:"Prompt Injection", definition:"An attack against large language model applications where crafted input overrides system instructions or manipulates the model into unintended actions. Indirect prompt injection hides malicious instructions in content the model later processes, threatening AI agents and RAG pipelines." },
  { term:"Model Inversion / Membership Inference", definition:"Model inversion reconstructs sensitive training data from a model's outputs, while membership inference determines whether a specific record was in the training set. Both are privacy attacks against ML models, motivating differential privacy defenses." },
  { term:"AI Bill of Materials", definition:"An emerging inventory documenting the components of an AI system, including models, datasets, and dependencies, to support transparency and supply-chain assurance. It extends SBOM concepts to the unique risks of machine-learning artifacts." },
  { term:"Cloud Shared Responsibility Model", definition:"A framework delineating which security duties belong to the cloud provider versus the customer, varying by service model (IaaS, PaaS, SaaS). Misunderstanding the boundary is a leading cause of cloud breaches, especially for data and configuration." },
  { term:"Cloud Control Plane vs Data Plane", definition:"The control plane manages and configures cloud resources via APIs, while the data plane carries actual workload traffic and data. Compromise of control-plane credentials is especially severe because it enables broad resource manipulation and pivoting." },
  { term:"IMDS / SSRF in Cloud", definition:"The Instance Metadata Service exposes credentials and configuration to cloud instances, and server-side request forgery can trick a vulnerable app into retrieving those credentials. IMDSv2's session-token requirement mitigates SSRF-based metadata theft." },
  { term:"Resource-Based vs Identity-Based Policy", definition:"Identity-based policies attach permissions to a principal (user, role), while resource-based policies attach directly to a resource specifying who may access it. Cross-account access and privilege-escalation paths often hinge on the interaction between the two." },
  { term:"Cloud Workload Identity Federation", definition:"A mechanism allowing workloads to assume cloud roles using external identity-provider tokens instead of long-lived static credentials. It eliminates stored access keys, reducing the risk of credential leakage in CI/CD and multi-cloud scenarios." },
  { term:"Landing Zone", definition:"A pre-configured, secure, and scalable multi-account cloud foundation with baseline guardrails, networking, identity, and logging. It enforces governance and consistent security controls from the outset of cloud adoption at scale." },
  { term:"Cloud Detection and Response", definition:"The practice of collecting and analyzing cloud audit logs, flow logs, and control-plane events to detect and respond to cloud-native threats. It addresses attack techniques unique to APIs, IAM, and ephemeral resources that traditional tools miss." },
  { term:"Blast Radius", definition:"The scope of damage or resources an attacker could reach if a given identity, credential, or component is compromised. Minimizing blast radius through segmentation and least privilege is a core resilience and zero-trust objective." },
  { term:"Chaos Engineering (Security)", definition:"The deliberate injection of controlled failures or attack conditions into systems to validate resilience and detection under adverse scenarios. Security chaos experiments verify that controls and responses behave as designed under real stress." },
  { term:"Cyber Resilience (NIST 800-160 Vol 2)", definition:"The ability to anticipate, withstand, recover from, and adapt to adverse cyber conditions, stresses, and attacks. It emphasizes that systems must continue delivering essential functions even while compromised, beyond mere prevention." },
  { term:"Threat-Informed Defense", definition:"An approach that continuously aligns defensive controls, detection, and testing to the specific adversary behaviors most relevant to the organization, often mapped to ATT&CK. It prioritizes defensive investment based on real threat intelligence rather than compliance alone." },
  { term:"Recovery Time/Point Objective", definition:"RTO is the maximum tolerable time to restore a service after disruption, and RPO is the maximum acceptable amount of data loss measured in time. Together they drive backup frequency, replication, and disaster-recovery architecture decisions." },
  { term:"Immutable Backups / Air-Gapped Backups", definition:"Backups that cannot be altered or deleted for a defined retention period (WORM) or are isolated from the network. They are a primary defense against ransomware that seeks to encrypt or destroy recovery data." }
];
GLOSSARY_SECX.sort((a, b) => a.term.localeCompare(b.term, undefined, { sensitivity: 'base' }));
